        f32 motion_frame;
        f32 anim_frame;
        f32 anim_speed;
        s32 ga;
        Vec3f vel_air;
        Vec3f physics_vel_air;
        sb32 is_fastfall;
        sb32 is_reflect;
        sb32 is_absorb;
        sb32 is_shield;
        sb32 is_invisible;
        sb32 is_shadow_hide;
        sb32 is_playertag_hide;
        sb32 is_cliff_hold;
        sb32 is_jostle_ignore;
        sb32 is_hitstun;
        f32 damage_mul;
        s32 damage_player;
        s32 coll_ignore_line_id;
        u8 capture_immune_mask;
