    gNdsStageMPCliffClimbCommon2LoopGAAfterPhysics = 0u;
    gNdsStageMPCliffClimbCommon2LoopStatusAfterMap = 0u;
    gNdsStageMPCliffClimbCommon2LoopMotionAfterMap = 0u;
    gNdsStageMPCliffClimbCommon2LoopGAAfterMap = 0u;
