        target_fp->ga = nMPKineticsAir;
        target_fp->lr = 1;
        target_fp->status_vars.common.damage.hitstun_tics = 1;
        target_fp->physics.vel_air.x = 1.0F;
        target_fp->physics.vel_air.y = 2.0F;
