        Vec3f saved_air_wall_translate = target_root->translate.vec.f;
        f32 saved_air_wall_anim_frame = target_gobj->anim_frame;
        f32 saved_air_wall_anim_speed = saved_anim_speed;
        u32 air_wall_mask = 0u;

