#define NDS_STAGE_MPLIVEHIT_CATCH_SEARCH_SKIP_GHOST (1u << 9)
#define NDS_STAGE_MPLIVEHIT_CATCH_SEARCH_SKIP_BOSS (1u << 10)
#define NDS_STAGE_MPLIVEHIT_CATCH_SEARCH_SKIP_TSTAT (1u << 11)
